BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?ownerName ?ownerType WHERE {
  ?elem vocab:NamedElement_name "APS Black Box Specification TMT" .
  ?elem rdf:type vocab:block .
  OPTIONAL { ?elem vocab:Element_owner ?owner . ?owner vocab:NamedElement_name ?ownerName . ?owner rdf:type ?ownerType }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?qualifiedName ?type WHERE {
  ?elem vocab:NamedElement_name ?name . 
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("APS Black Box Specification TMT")))
  OPTIONAL { ?elem vocab:NamedElement_qualifiedName ?qualifiedName }
  ?elem rdf:type ?type .
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?qualifiedName ?owner ?ownerName WHERE {
  BIND(<http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Project%2520Systems%2520Engineering::01%2520Components::Operational::TMT%2520Observatory%2520System::Black%2520Box%2520Specifications%2520for%2520Suppliers::APS%2520Black%2520Box%2520Specification%2520TMT> AS ?elem)
  ?elem vocab:NamedElement_name ?name .
  OPTIONAL { ?elem vocab:NamedElement_qualifiedName ?qualifiedName }
  OPTIONAL { ?elem vocab:Element_owner ?owner . ?owner vocab:NamedElement_name ?ownerName }
}
LIMIT 25
